set(
  object: Recordable,
  path: PropPath,
  value: unknown,
  cb?: (object: Recordable, field: string, value: unknown) => void,
) {
  const sections = Array.isArray(path) ? path : path.split('.')
  const markRef = false
  while (sections.length > 1) {
    const section = sections.shift()!
    if (object instanceof Map)
      object = object.get(section) as Recordable
    else if (object instanceof Set)
      object = Array.from(object.values())[section] as Recordable
    else object = object[section] as Recordable
    if (this.refEditor.isRef(object))
      object = this.refEditor.get(object)
  }
  const field = sections[0]
  const item = this.refEditor.get(object)[field]
  if (cb) {
    cb(object, field, value)
  }
  else {
    if (this.refEditor.isRef(item))
      this.refEditor.set(item, value)
    else if (markRef)
      object[field] = value
    else
      object[field] = value
  }
}

export function* generateEventArg(
	options: TemplateCodegenOptions,
	name: string,
	start: number,
	directive = 'on',
	features?: VueCodeInformation,
): Generator<Code> {
	features ??= {
		...codeFeatures.semanticWithoutHighlight,
		...codeFeatures.navigationWithoutRename,
		...options.vueCompilerOptions.checkUnknownEvents
			? codeFeatures.verification
			: codeFeatures.doNotReportTs2353AndTs2561,
	};

	if (directive.length) {
		name = capitalize(name);
	}
	if (identifierRegex.test(camelize(name))) {
		const token = yield* startBoundary('template', start, features);
		yield directive;
		yield* generateCamelized(name, 'template', start, { __combineToken: token });
	}
	else {
		const token = yield* startBoundary('template', start, features);
		yield `'`;
		yield directive;
		yield* generateCamelized(name, 'template', start, { __combineToken: token });
		yield `'`;
		yield endBoundary(token, start + name.length);
	}
}
